function calculate({ initialPurchaseCost, annualMaintenanceCost, initialTrainingIntegrationCost, operationalLifespanYears, annualOperationalCost, estimatedAnnualStrategicBenefit, strategicAdvantageFactor, riskMitigationFactor, opportunityCostOfCapital, inflationRate }) {

  const discountRate = (opportunityCostOfCapital + inflationRate) / 100;

  // Ensure factors are within reasonable bounds [0, 1]
  const effectiveStrategicAdvantageFactor = Math.max(0, Math.min(1, strategicAdvantageFactor));
  const effectiveRiskMitigationFactor = Math.max(0, Math.min(1, riskMitigationFactor));

  // --- 1. Calculate Total Nominal Lifecycle Cost ---
  const initialTotalCost = initialPurchaseCost + initialTrainingIntegrationCost;
  const annualRecurringCost = annualMaintenanceCost + annualOperationalCost;
  const totalNominalLifecycleCost = initialTotalCost + (annualRecurringCost * operationalLifespanYears);

  // --- 2. Calculate Net Present Value (NPV) of Total Lifecycle Cost ---
  let npvTotalLifecycleCost = initialTotalCost; // Year 0 cost
  for (let i = 1; i <= operationalLifespanYears; i++) {
    npvTotalLifecycleCost += annualRecurringCost / Math.pow(1 + discountRate, i);
  }

  // --- 3. Calculate Total Nominal Strategic Benefit ---
  // Cap the total benefit multiplier to prevent unrealistically high benefits from factors
  const benefitMultiplier = 1 + effectiveStrategicAdvantageFactor + effectiveRiskMitigationFactor;
  const cappedBenefitMultiplier = Math.min(3, benefitMultiplier); // Cap at 3x the estimated annual benefit for prudence

  const annualAdjustedStrategicBenefit = estimatedAnnualStrategicBenefit * cappedBenefitMultiplier;
  const totalNominalStrategicBenefit = annualAdjustedStrategicBenefit * operationalLifespanYears;

  // Handle edge case where estimatedAnnualStrategicBenefit is 0 or negative
  if (estimatedAnnualStrategicBenefit <= 0 || annualAdjustedStrategicBenefit <= 0) {
      return {
          totalNominalLifecycleCost: totalNominalLifecycleCost,
          npvTotalLifecycleCost: npvTotalLifecycleCost,
          totalNominalStrategicBenefit: 0,
          npvTotalStrategicBenefit: 0,
          nominalCostBenefitRatio: Infinity, // Or NaN, depending on desired representation
          npvCostBenefitRatio: Infinity
      };
  }

  // --- 4. Calculate Net Present Value (NPV) of Total Strategic Benefit ---
  let npvTotalStrategicBenefit = 0;
  for (let i = 1; i <= operationalLifespanYears; i++) {
    npvTotalStrategicBenefit += annualAdjustedStrategicBenefit / Math.pow(1 + discountRate, i);
  }

  // --- 5. Calculate Cost-Benefit Ratios ---
  const nominalCostBenefitRatio = totalNominalLifecycleCost / totalNominalStrategicBenefit;
  const npvCostBenefitRatio = npvTotalLifecycleCost / npvTotalStrategicBenefit;

  return {
    totalNominalLifecycleCost: totalNominalLifecycleCost,
    npvTotalLifecycleCost: npvTotalLifecycleCost,
    totalNominalStrategicBenefit: totalNominalStrategicBenefit,
    npvTotalStrategicBenefit: npvTotalStrategicBenefit,
    nominalCostBenefitRatio: nominalCostBenefitRatio,
    npvCostBenefitRatio: npvCostBenefitRatio
  };
}
